    def knapsack(self, weights: list[int], values: list[int], W: int) -> int:
        dp = [0] * (W + 1)
        for wt, val in zip(weights, values):
            for w in range(W, wt - 1, -1):
                dp[w] = max(dp[w], dp[w - wt] + val)
        return dp[W]

